    fn from(perm: MapPerm) -> Self {
        *Self::new_valid()
            .set_U(perm.contains(MapPerm::U))
            .set_G(!perm.contains(MapPerm::U))
            .set_R(perm.contains(MapPerm::R))
            .set_W(perm.contains(MapPerm::W))
