    ///init app context
    pub fn app_init_context(
        entry: usize,
        sp: usize,
        // kernel_sp: usize,
    ) -> Self {
        let mut sstatus = sstatus::read();
        sstatus.set_spp(SPP::User);
        sstatus.set_sie(false);
        let mut cx = Self {
            user_gp: GPRegs::new(),
            sstatus,
            sepc: entry,
            kernel_sp: 0,
            kernal_ra: 0,
            kernel_s: [0; 12],
            kernel_fp: 0,
            kernel_tp: 0,
            float_regs: UserFloatRegs::new(),
        };
        cx.set_sp(sp);

