#[inline(always)]
pub fn check_magic(elf: &ElfFile) -> SysResult<()> {
    const ELF_MAGIC: [u8; 4] = [0x7f, 0x45, 0x4c, 0x46];
    if elf.header.pt1.magic == ELF_MAGIC {
        Ok(())
    } else {
        Err(Errno::ENOEXEC)
    }
